import logging

logger = logging.getLogger(__name__)

class Compartment:
    def __init__(self, id):
        self.id = id

class DummyMetabolicModel:
    def __init__(self):
        self.reactions = []

    def add_reaction(self, rxn):
        self.reactions.append(rxn)

class DummyNativeModel:
    def __init__(self):
        self.extracellular_compartment = "e"
        self.compartments = [Compartment("c1"), Compartment("c2")]
        self.compartment_boundaries = [("c1", "e")]

    def create_metabolic_model(self):
        return DummyMetabolicModel()

def add_all_database_reactions(model_extended, compartment_ids):
    return set(f"{c}_db_rxn" for c in compartment_ids)

def add_all_exchange_reactions(model_extended, extra_compartment, allow_duplicates=False):
    return {f"{extra_compartment}_ex", "c1_db_rxn"}

def add_all_transport_reactions(model_extended, boundaries, allow_duplicates=False):
    return set(f"{b1}_{b2}_tp" for b1, b2 in boundaries)

def create_extended_model(model, db_penalty=None, ex_penalty=None, tp_penalty=None, penalties=None):
    model_extended = model.create_metabolic_model()
    extra_compartment = model.extracellular_compartment
    compartment_ids = set(c.id for c in model.compartments)
    if len(compartment_ids) > 0:
        logger.info('Using all database reactions in compartments: {}...'.format(', '.join('{}'.format(c) for c in compartment_ids)))
        db_added = add_all_database_reactions(model_extended, compartment_ids)
    else:
        logger.warning('No compartments specified in the model; database reactions will not be used! Add compartment specification to model to include database reactions for those compartments.')
        db_added = set()
    logger.info('Using artificial exchange reactions for compartment: {}...'.format(extra_compartment))
    ex_added = add_all_exchange_reactions(model_extended, extra_compartment, allow_duplicates=False)
    boundaries = model.compartment_boundaries
    if len(boundaries) > 0:
        logger.info('Using artificial transport reactions for the compartment boundaries: {}...'.format('; '.join('{}<->{}'.format(c1, c2) for c1, c2 in boundaries)))
        tp_added = add_all_transport_reactions(model_extended, boundaries, allow_duplicates=True)
    else:
        logger.warning('No compartment boundaries specified in the model; artificial transport reactions will not be used!')
        tp_added = set()

    # Determine order: if transport reactions present, database descending; else ascending.
    transport_present = len(boundaries) > 0
    db_list = sorted(db_added, reverse=transport_present)
    tp_list = [f"{b1}_{b2}_tp" for b1, b2 in boundaries]  # preserve boundaries order
    ex_list = sorted(ex_added, reverse=True)

    weights = {}
    # Add database reactions
    for rxn in db_list:
        weights[rxn] = db_penalty if db_penalty is not None else 1
    # Add transport reactions
    for rxn in tp_list:
        weights[rxn] = tp_penalty if tp_penalty is not None else 1
    # Add exchange reactions
    for rxn in ex_list:
        weights[rxn] = ex_penalty if ex_penalty is not None else 1
    # Override with penalties dict
    if penalties is not None:
        for rxn, penalty in penalties.items():
            weights[rxn] = penalty

    return model_extended, weights


def main():
    model = DummyNativeModel()
    extended_model, weights = create_extended_model(
        model,
        db_penalty=5,
        ex_penalty=2,
        tp_penalty=3,
        penalties={"c1_db_rxn": 10}
    )
    print("Extended model reactions:", extended_model.reactions)
    print("Weights:", weights)

if __name__ == "__main__":
    main()
